54	[[nodiscard]] constexpr MeasurementRegime regime_of(MeasurementCategory category) noexcept {
55	    switch (category) {
56	        // Thesis 03_messsystem_prtart.tex:382-386: zeit-/observer-basierte Kategorien laufen mit eigener
57	        // Apparatur immer; 06_evaluation_methodology.tex:119-126: nicht vom privilegierten PMC-Regime gated.
58	        case MeasurementCategory::CLU:
59	        case MeasurementCategory::MEMORY_FOOTPRINT:
60	        case MeasurementCategory::LATENCY_MEAN:
61	        case MeasurementCategory::LATENCY_P50:
62	        case MeasurementCategory::LATENCY_P95:
63	        case MeasurementCategory::LATENCY_P99:
64	        case MeasurementCategory::LATENCY_P999:
65	        case MeasurementCategory::THROUGHPUT:
66	        case MeasurementCategory::FILL_BUFFER_OCCUPANCY: return MeasurementRegime::TimeObserver;
67	
68	        // Thesis 03_messsystem_prtart.tex:382-386: PMC-/zaehlerbasierte Kategorien sind getrennt;
69	        // 06_evaluation_methodology.tex:119-126 nennt Cache-, dTLB-, Branch-Misses und IPC/CPI.
70	        // ENERGY_J ist code-verankert ueber PmcCounters::energy_micro_joules.
71	        case MeasurementCategory::CACHE_MISS_L1:
72	        case MeasurementCategory::CACHE_MISS_L2:
73	        case MeasurementCategory::CACHE_MISS_L3:
74	        case MeasurementCategory::DTLB_MISS:
75	        case MeasurementCategory::BRANCH_MISS:
76	        case MeasurementCategory::IPC_CPI:
77	        case MeasurementCategory::ENERGY_J: return MeasurementRegime::PmcCounter;
78	    }
79	    return MeasurementRegime::TimeObserver;
80	}
