100	[[nodiscard]] constexpr bool regime_mapping_is_complete() noexcept {
101	    std::size_t pmc_count           = 0;
102	    std::size_t time_observer_count = 0;
103	    for (auto const category : kAllMeasurementCategories) {
104	        MeasurementRegime const regime = regime_of(category);
105	        if (regime == MeasurementRegime::PmcCounter) {
106	            if (!contains(kPmcCounterCategories, category)) return false;
107	            ++pmc_count;
108	        } else {
109	            if (!contains(kTimeObserverCategories, category)) return false;
110	            ++time_observer_count;
111	        }
112	    }
113	    return pmc_count == kPmcCounterCategories.size() && time_observer_count == kTimeObserverCategories.size() &&
114	           (pmc_count + time_observer_count) == kAllMeasurementCategories.size();
115	}
