147	template <class Derived>
148	struct SystemAxis {
149	    [[nodiscard]] static constexpr auto              categories() noexcept { return Derived::do_categories(); }
150	    [[nodiscard]] static constexpr MeasurementRegime regime() noexcept { return detail::regime_for_axis<Derived>(); }
151	
152	    [[nodiscard]] constexpr bool available() const noexcept {
153	        if constexpr (requires(Derived const& derived) {
154	                          { derived.do_available() } -> std::convertible_to<bool>;
155	                      }) {
156	            return static_cast<bool>(derived().do_available());
157	        } else {
158	            return true;
159	        }
160	    }
161	
162	    constexpr void collect(SystemAxisSample& sample) const noexcept {
163	        if (!available()) {
164	            invalidate(sample);
165	            return;
166	        }
167	        derived().do_collect(sample);
168	    }
169	
170	protected:
171	    constexpr SystemAxis() noexcept = default;
172	
173	    static constexpr void invalidate(SystemAxisSample& sample) noexcept {
174	        sample.value = 0;
175	        sample.valid = false;
176	    }
177	
178	private:
179	    [[nodiscard]] constexpr Derived const& derived() const noexcept { return static_cast<Derived const&>(*this); }
180	};
