182	template <class A>
183	concept SystemAxisConcept =
184	    std::derived_from<A, SystemAxis<A>> && std::is_empty_v<SystemAxis<A>> && (!std::is_polymorphic_v<SystemAxis<A>>) &&
185	    requires(A const& axis, SystemAxisSample& sample) {
186	        { A::categories() };
187	        { A::regime() } -> std::same_as<MeasurementRegime>;
188	        { axis.available() } -> std::same_as<bool>;
189	        { axis.collect(sample) } -> std::same_as<void>;
190	    };
