192	struct WallClockSystemAxis final : SystemAxis<WallClockSystemAxis> {
193	    std::int64_t  total_ns = 0;
194	    std::uint64_t op_count = 0;
195	
196	    constexpr WallClockSystemAxis(std::int64_t total_ns_, std::uint64_t op_count_) noexcept
197	        : total_ns(total_ns_), op_count(op_count_) {}
198	
199	    [[nodiscard]] static constexpr auto do_categories() noexcept {
200	        return std::array{MeasurementCategory::LATENCY_MEAN, MeasurementCategory::THROUGHPUT};
201	    }
202	
203	    constexpr void do_collect(SystemAxisSample& sample) const noexcept {
204	        switch (sample.category) {
205	            case MeasurementCategory::LATENCY_MEAN:
206	                if (op_count == 0 || total_ns < 0) {
207	                    invalidate(sample);
208	                    return;
209	                }
210	                sample.value = static_cast<std::uint64_t>(total_ns) / op_count;
211	                sample.valid = true;
212	                return;
213	
214	            case MeasurementCategory::THROUGHPUT:
215	                if (total_ns <= 0) {
216	                    invalidate(sample);
217	                    return;
218	                }
219	                sample.value = static_cast<std::uint64_t>((static_cast<long double>(op_count) * 1'000'000'000.0L) /
220	                                                          static_cast<long double>(total_ns));
221	                sample.valid = true;
222	                return;
223	
224	            case MeasurementCategory::LATENCY_P50:
225	            case MeasurementCategory::LATENCY_P95:
226	            case MeasurementCategory::LATENCY_P99:
227	            case MeasurementCategory::LATENCY_P999:
228	                // honest-0: total_ns/op_count ist ein MITTELWERT — ihn als Perzentil zu etikettieren
229	                // waere ein Phantomwert. Echte Perzentile liefert das HdrHistogramm (AP-8/#242).
230	                invalidate(sample);
231	                return;
232	
233	            default: invalidate(sample); return;
234	        }
235	    }
236	};
