253	        switch (sample.category) {
254	            case MeasurementCategory::CLU: {
255	                // Cache-Line-AUSLASTUNG (Thesis 03:383) = field_bytes / (cache_lines * 64), hier als Prozent.
256	                // Der rohe cache_lines-Zaehler waere die INVERSE Metrik (Review wf_f1604ba3, CONFIRMED-major).
257	                std::uint64_t const field_bytes = snapshot->axis_stats[5][2];
258	                std::uint64_t const cache_lines = snapshot->axis_stats[5][3];
259	                if (cache_lines == 0) {
260	                    invalidate(sample);
261	                    return;
262	                }
263	                sample.value = (field_bytes * 100u) / (cache_lines * 64u);
264	                sample.valid = true;
265	                return;
266	            }
267	            case MeasurementCategory::MEMORY_FOOTPRINT:
268	                // honest-0: der Thesis-Kanon verlangt bytes_in_use_peak (05_evaluation.tex:94-95); das T6-Schema
269	                // traegt nur den Momentanwert bytes_in_use — als Footprint etikettiert verzerrte er CoW-lastige
270	                // Layouts (Peak >> Endstand). Bis eine peak-Spalte (golden-neutraler END-Append) existiert: invalid.
271	            case MeasurementCategory::FILL_BUFFER_OCCUPANCY:
272	                // honest-0: T17 queuing_q1.peak_size ist ein SOFTWARE-Operations-Puffer; die Thesis-Kategorie meint
273	                // Hardware-Line-Fill-Buffer (P25 Mahling, 03_state_of_the_art:543) — physisch unverwandt, kein Proxy.
274	            default: invalidate(sample); return;
275	        }
276	    }
