59	/// Vollstaendiges, vendor-neutrales Mess-Delta: Wert + Gueltigkeit JE Event (honest-Doktrin —
60	/// value 0 mit valid=true ist eine echte Null-Messung, valid=false heisst NICHT gemessen).
61	struct MeasuredDelta {
62	    std::array<std::uint64_t, kMeasuredEventCount> value{};
63	    std::array<bool, kMeasuredEventCount>          valid{};
64	
65	    [[nodiscard]] constexpr std::uint64_t of(MeasuredEvent e) const noexcept {
66	        return value[static_cast<std::size_t>(e)];
67	    }
68	    [[nodiscard]] constexpr bool is_valid(MeasuredEvent e) const noexcept { return valid[static_cast<std::size_t>(e)]; }
69	};
